class Solution {
public:
    int findCityWithSmallestNeighbors(
        int totalCities,
        vector<vector<int>>& roadConnections,
        int maxDistance
    ) {
        const int INF = 1e9;
        vector<vector<int>> dist(totalCities, vector<int>(totalCities, INF));

        for (int i = 0; i < totalCities; i++)
            dist[i][i] = 0;

        // Build graph
        for (auto &e : roadConnections) {
            int u = e[0], v = e[1], w = e[2];
            dist[u][v] = min(dist[u][v], w);
            dist[v][u] = min(dist[v][u], w);
        }

        // Floyd–Warshall
        for (int k = 0; k < totalCities; k++) {
            for (int i = 0; i < totalCities; i++) {
                for (int j = 0; j < totalCities; j++) {
                    if (dist[i][k] + dist[k][j] < dist[i][j]) {
                        dist[i][j] = dist[i][k] + dist[k][j];
                    }
                }
            }
        }

        int minCnt = INT_MAX;
        int ans = -1;

        for (int i = 0; i < totalCities; i++) {
            int cnt = 0;
            for (int j = 0; j < totalCities; j++) {
                if (i != j && dist[i][j] <= maxDistance)
                    cnt++;
            }

            if (cnt < minCnt || (cnt == minCnt && i > ans)) {
                minCnt = cnt;
                ans = i;
            }
        }

        return ans;
    }
};

