typedef struct Edge {
    int to;
    int weight;
    struct Edge *next;
} Edge;

typedef struct {
    int node;
    int dist;
} HeapNode;

typedef struct {
    HeapNode *data;
    int size;
    int capacity;
} MinHeap;

MinHeap* createHeap(int capacity) {
    MinHeap *heap = (MinHeap *)malloc(sizeof(MinHeap));
    heap->data = (HeapNode *)malloc(capacity * sizeof(HeapNode));
    heap->size = 0;
    heap->capacity = capacity;
    return heap;
}

void swap(HeapNode *a, HeapNode *b) {
    HeapNode temp = *a;
    *a = *b;
    *b = temp;
}

void heapifyUp(MinHeap *heap, int idx) {
    while (idx > 0) {
        int parent = (idx - 1) / 2;
        if (heap->data[idx].dist < heap->data[parent].dist) {
            swap(&heap->data[idx], &heap->data[parent]);
            idx = parent;
        } else {
            break;
        }
    }
}

void heapifyDown(MinHeap *heap, int idx) {
    while (1) {
        int smallest = idx;
        int left = 2 * idx + 1;
        int right = 2 * idx + 2;

        if (left < heap->size && heap->data[left].dist < heap->data[smallest].dist)
            smallest = left;
        if (right < heap->size && heap->data[right].dist < heap->data[smallest].dist)
            smallest = right;

        if (smallest != idx) {
            swap(&heap->data[idx], &heap->data[smallest]);
            idx = smallest;
        } else {
            break;
        }
    }
}

void push(MinHeap *heap, int node, int dist) {
    if (heap->size >= heap->capacity) return;
    heap->data[heap->size].node = node;
    heap->data[heap->size].dist = dist;
    heapifyUp(heap, heap->size);
    heap->size++;
}

HeapNode pop(MinHeap *heap) {
    HeapNode result = heap->data[0];
    heap->size--;
    if (heap->size > 0) {
        heap->data[0] = heap->data[heap->size];
        heapifyDown(heap, 0);
    }
    return result;
}

int isEmpty(MinHeap *heap) {
    return heap->size == 0;
}

void addEdge(Edge **graph, int from, int to, int weight) {
    Edge *newEdge = (Edge *)malloc(sizeof(Edge));
    newEdge->to = to;
    newEdge->weight = weight;
    newEdge->next = graph[from];
    graph[from] = newEdge;
}

int dijkstra(Edge **graph, int totalCities, int source, int maxDistance) {
    int *dist = (int *)malloc(totalCities * sizeof(int));
    for (int i = 0; i < totalCities; i++) {
        dist[i] = INF;
    }
    dist[source] = 0;

    MinHeap *heap = createHeap(totalCities * 100);
    push(heap, source, 0);

    while (!isEmpty(heap)) {
        HeapNode current = pop(heap);
        int u = current.node;
        int d = current.dist;

        if (d > dist[u]) continue;

        for (Edge *e = graph[u]; e != NULL; e = e->next) {
            int v = e->to;
            int newDist = dist[u] + e->weight;
            if (newDist < dist[v]) {
                dist[v] = newDist;
                push(heap, v, newDist);
            }
        }
    }

    int count = 0;
    for (int i = 0; i < totalCities; i++) {
        if (i != source && dist[i] <= maxDistance) {
            count++;
        }
    }

    free(dist);
    free(heap->data);
    free(heap);

    return count;
}

int findCityWithSmallestNeighbors(
    int totalCities,
    int roadConnections[][3],
    int numRoads,
    int maxDistance
) {
    // Build adjacency list
    Edge **graph = (Edge **)calloc(totalCities, sizeof(Edge *));

    for (int i = 0; i < numRoads; i++) {
        int u = roadConnections[i][0];
        int v = roadConnections[i][1];
        int w = roadConnections[i][2];
        addEdge(graph, u, v, w);
        addEdge(graph, v, u, w);
    }

    int minCnt = INT_MAX;
    int ans = -1;

    for (int i = 0; i < totalCities; i++) {
        int cnt = dijkstra(graph, totalCities, i, maxDistance);
        if (cnt < minCnt || (cnt == minCnt && i > ans)) {
            minCnt = cnt;
            ans = i;
        }
    }

    // Free graph
    for (int i = 0; i < totalCities; i++) {
        Edge *current = graph[i];
        while (current != NULL) {
            Edge *temp = current;
            current = current->next;
            free(temp);
        }
    }
    free(graph);

    return ans;
}

