        const INF = 1e9;

        // Distance matrix
        const dist = Array.from({ length: totalCities }, () =>
            Array(totalCities).fill(INF)
        );

        for (let i = 0; i < totalCities; i++) {
            dist[i][i] = 0;
        }

        // Build graph
        for (const [u, v, w] of roadConnections) {
            dist[u][v] = Math.min(dist[u][v], w);
            dist[v][u] = Math.min(dist[v][u], w);
        }

        // Floyd–Warshall
        for (let k = 0; k < totalCities; k++) {
            for (let i = 0; i < totalCities; i++) {
                for (let j = 0; j < totalCities; j++) {
                    const nd = dist[i][k] + dist[k][j];
                    if (nd < dist[i][j]) {
                        dist[i][j] = nd;
                    }
                }
            }
        }

        let minCount = Infinity;
        let answer = -1;

        for (let i = 0; i < totalCities; i++) {
            let count = 0;
            for (let j = 0; j < totalCities; j++) {
                if (i !== j && dist[i][j] <= maxDistance) {
                    count++;
                }
            }

            // tie-breaking: greatest index
            if (count < minCount || (count === minCount && i > answer)) {
                minCount = count;
                answer = i;
            }
        }

        return answer;
    }
}
